bool HasCitationAnchor(absl::string_view text) {
  for (size_t i = 0; i < text.size(); ++i) {
    if (text[i] != '[') {
      continue;
    }
    size_t j = i + 1;
    bool has_digit = false;
    while (j < text.size() && text[j] >= '0' && text[j] <= '9') {
      has_digit = true;
      ++j;
    }
    if (has_digit && j < text.size() && text[j] == ']') {
      return true;
    }
  }
  return false;
}

